import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Login from './pages/Login';

import GroupDetails from './pages/GroupDetails';
import MyGroups from './pages/MyGroups';
import CreateGroup from './pages/CreateGroup';

function App() {
    const [darkMode, setDarkMode] = useState(false);

    // Lecture du mode sombre stocké localement
   // Exemple de gestion du mode sombre dans un composant React
useEffect(() => {
    const isDarkMode = localStorage.getItem('darkMode') === 'true';
    if (isDarkMode) {
        document.body.classList.add('dark');
    } else {
        document.body.classList.remove('dark');
    }
}, []);

const toggleDarkMode = () => {
    const isDark = document.body.classList.toggle('dark');
    localStorage.setItem('darkMode', isDark);
};

// Un bouton pour activer/désactiver le mode sombre
<button onClick={toggleDarkMode}>Basculer le mode sombre</button>


    return (
        <Router>
            <div className={`app-container ${darkMode ? 'dark' : ''}`}>
                <Navbar toggleDarkMode={toggleDarkMode} darkMode={darkMode} />

                <Routes>
                    <Route path="/" element={<Login />} />
                    <Route path="/my-groups" element={<MyGroups />} />
                    <Route path="/groups/:groupId" element={<GroupDetails />} />
                    <Route path="/create-group" element={<CreateGroup />} />
                    <Route path="*" element={<Login />} />
                </Routes>
            </div>
        </Router>
    );
}

export default App;
